from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI instance and parser
    cli = LeannCLI()
    parser = cli.create_parser()

    # Parse the arguments
    args = parser.parse_args(args_list)

    # Initialize base configuration
    config: Dict[str, Any] = {}

    # Common configuration parameters
    if hasattr(args, 'index_path') and args.index_path:
        config['index_path'] = str(args.index_path)

    if hasattr(args, 'backend') and args.backend:
        config['backend'] = args.backend

    if hasattr(args, 'backend_config') and args.backend_config:
        config['backend_config'] = args.backend_config

    if hasattr(args, 'embedding_model') and args.embedding_model:
        config['embedding_model'] = args.embedding_model

    if hasattr(args, 'embedding_config') and args.embedding_config:
        config['embedding_config'] = args.embedding_config

    if hasattr(args, 'metadata') and args.metadata:
        config['metadata'] = args.metadata

    # Command-specific parameters
    if command_type == "build":
        if hasattr(args, 'docs_paths') and args.docs_paths:
            config['docs_paths'] = [str(path) for path in args.docs_paths]

        if hasattr(args, 'chunk_size') and args.chunk_size:
            config['chunk_size'] = args.chunk_size

        if hasattr(args, 'chunk_overlap') and args.chunk_overlap:
            config['chunk_overlap'] = args.chunk_overlap

    elif command_type == "search":
        if hasattr(args, 'query') and args.query:
            config['query'] = args.query

        if hasattr(args, 'top_k') and args.top_k:
            config['top_k'] = args.top_k

        if hasattr(args, 'metadata_filters') and args.metadata_filters:
            config['metadata_filters'] = args.metadata_filters

    # Handle verbosity settings if present
    if hasattr(args, 'verbose') and args.verbose:
        config['verbose'] = args.verbose

    if hasattr(args, 'quiet') and args.quiet:
        config['quiet'] = args.quiet

    return config

